code = """import json

# Load data from storage
reviews = locals()['var_functions.query_db:12']
la_businesses = locals()['var_functions.query_db:30']

# Map business IDs to names
business_map = {}
for biz in la_businesses:
    business_map[biz['gmap_id']] = biz['name']

# Calculate average ratings
biz_ratings = {}
for review in reviews:
    gmap_id = review['gmap_id']
    if gmap_id in business_map:
        if gmap_id not in biz_ratings:
            biz_ratings[gmap_id] = []
        biz_ratings[gmap_id].append(int(review['rating']))

# Compute averages and create results
results = []
for gmap_id, ratings in biz_ratings.items():
    avg = sum(ratings) / len(ratings)
    results.append({
        'rank': 0,
        'name': business_map[gmap_id],
        'rating': round(avg, 2),
        'reviews': len(ratings)
    })

# Sort by rating descending and rank
results = sorted(results, key=lambda x: x['rating'], reverse=True)
for i, item in enumerate(results):
    item['rank'] = i + 1

# Get top 5
top5 = results[:5]

# Format answer
answer = "Top 5 Businesses in Los Angeles, California by Highest Average Rating:\n\n"
for biz in top5:
    answer += str(biz['rank']) + ". " + biz['name'] + "\n"
    answer += "   Average Rating: " + str(biz['rating']) + "/5.0" + "\n"
    answer += "   Number of Reviews: " + str(biz['reviews']) + "\n\n" 

print('__RESULT__:')
print(answer)"""

